def validate_file_path(v: str) -> str:
    """Check that the path is valid according to regex"""
    if not re.match(r"^(\/[a-zA-Z0-9_-]+)+\/[a-zA-Z0-9_-]+\.[a-zA-Z0-9_-]+$", v):
        raise ValueError(f"Path {v} is not valid")
    return v

