class CreateClip(UnvalidatedClip):
    words: Sequence[Word]

    @property
    def start_ms(self) -> float:
        value = self.words[0].start
        if value < 100:
            warnings.warn("start_ms is very small. Ensure it's in milliseconds.")
        return value

    @property
    def end_ms(self) -> float:
        value = self.words[-1].end
        if value < 100:
            warnings.warn("end_ms is very small. Ensure it's in milliseconds.")
        return value

    @property
    def duration_ms(self) -> float:
        return self.end_ms - self.start_ms

    @field_validator("words")
    def check_words_length(cls, values: list["Word"]) -> list["Word"]:
        if not values:
            raise ValueError("Clip must have at least one word.")
        return values


