TModelOut = TypeVar("TModelOut", bound=SQLModel)


class SqlModelDatabase(AbstractDatabase["SqlModelDatabase"]):
    def __init__(self, database_url: str):
        self.engine = create_engine(database_url, pool_pre_ping=True)
        self.employee = None

    class Operations(AbstractDatabase.Operations):
        def __init__(self, database: "SqlModelDatabase"):
            self.database = database
            
        def close(self) -> None:
            self.database.engine.dispose()

    def as_employee(self, employee: Employee):
        self.employee = employee
        return self

    @public
    def get_employee(
        self, session: Session, employee_id: Union[str, UUID]
    ) -> Optional[Employee]:
        return session.exec(select(Employee).where(Employee.id == employee_id)).first()

    def permissions_set_session_variables(self, session: Session, employee: Employee):
        """Same as set_session_variables, but without any kind of permissions. Use at your own risk."""
        session.execute(text(f"SET app.current_company_id = '{employee.company_id}'"))
        session.execute(
            text(
                f"SET app.current_permission_level = '{employee.permission_level.name}'"
            )
        )
        session.execute(text(f"SET app.current_employee_id = '{employee.id}'"))
        session.commit()

    @public
    def set_session_variables(self, session: Session, employee: Employee):
        session.execute(text(f"SET app.current_company_id = '{employee.company_id}'"))
        session.execute(
            text(f"SET app.current_permission_level = '{employee.permission_level}'")
        )
        session.commit()

    @public
    def clear_session_variables(self, session: Session):
        session.execute(text("RESET app.current_company_id"))
        session.execute(text("RESET app.current_permission_level"))
        session.execute(text("RESET app.current_employee_id"))
        session.commit()

    def permissions_clear_session_variables(self, session: Session):
        session.execute(text("RESET app.current_company_id"))
        session.execute(text("RESET app.current_permission_level"))
        session.execute(text("RESET app.current_employee_id"))
        session.commit()

    def get_session_for_employee(self, public: bool = False) -> Session:
        if public:
            return Session(self.engine, expire_on_commit=False)
        if self.employee is None:
            raise PermissionError("Employee not set for this session.")
        return Session(self.engine, expire_on_commit=False)

    @public
    def authenticate_employee(
        self, session: Session, email: str, password: str
    ) -> Optional[Employee]:
        employee = session.exec(select(Employee).where(Employee.email == email)).first()

        if employee:
            print(employee.hashed_password.decode("utf-8"))
            if pbkdf2_sha256.verify(password, employee.hashed_password.decode("utf-8")):
                print("Password verified successfully")
                return employee
            else:
                print("Password verification failed")
        else:
            print("No employee found with this email")

        return None

    @write
    def save_employee(
        self,
        session: Session,
        unvalidated_employee: CreateEmployee,
        company_id: UUID,
    ) -> Employee:
        hashed_password = pbkdf2_sha256.hash(unvalidated_employee.password).encode(
            "utf-8"
        )
        company = session.exec(select(Company).where(Company.id == company_id)).first()
        if company is None:
            raise ValueError(f"Company with id {company_id} not found")
        print(unvalidated_employee.model_dump())
        employee_to_validate = Employee(
            **unvalidated_employee.model_dump(),
            hashed_password=hashed_password,
            company_id=company_id,
        )
        print("employee_to_validate.company_id", employee_to_validate.company_id)
        employee = Employee.model_validate(employee_to_validate)
        company.employees.append(employee)
        session.commit()
        session.refresh(employee)
        return employee

    @write
    def update_employee(
        self,
        session: Session,
        employee_id: str | UUID,
        values_to_update: dict[str, Any],
    ) -> Employee:
        employee = session.exec(
            select(Employee).where(Employee.id == employee_id)
        ).first()
        if employee is None:
            raise ValueError(f"Employee with id {employee_id} not found")
        for key, value in values_to_update.items():
            setattr(employee, key, value)
        session.add(employee)
        session.commit()
        session.refresh(employee)
        return employee

    @public
    def save_company_and_employee(
        self,
        session: Session,
        unvalidated_company: UnvalidatedCompany,
        unvalidated_employee: CreateEmployee,
    ) -> Tuple[Company, Employee]:
        # check if employee exists
        existing_employee = session.exec(
            select(Employee).where(Employee.email == unvalidated_employee.email)
        ).first()
        if existing_employee:
            raise ValueError(
                f"Employee with email {unvalidated_employee.email} already exists"
            )
        company = Company.model_validate(unvalidated_company)
        session.add(company)
        session.commit()
        session.refresh(company)
        hashed_password = pbkdf2_sha256.hash(unvalidated_employee.password).encode(
            "utf-8"
        )
        employee_to_validate = Employee(
            **unvalidated_employee.model_dump(),
            hashed_password=hashed_password,
            company_id=company.id,
        )
        employee = Employee.model_validate(employee_to_validate)
        company.employees.append(employee)
        session.commit()
        session.refresh(employee)

        return company, employee

    def _save(
        self,
        session: Session,
        model: SQLModel,
        output_model: Type[TModelOut],
        joinedload_keys: List[Callable[[TModelOut], Any]] = [],
    ) -> TModelOut:
        valid_model = output_model.model_validate(model)
        session.add(valid_model)
        session.commit()
        if joinedload_keys:
            model_to_return = session.exec(
                select(output_model)
                .options(joinedload(*joinedload_keys))
                .where(output_model.id == valid_model.id)
            ).first()
        else:
            model_to_return = session.exec(
                select(output_model).where(output_model.id == valid_model.id)
            ).first()
        if model_to_return is None:
            raise ValueError(
                f"{output_model.__name__} with id {valid_model.id} not found"
            )
        return model_to_return

