    @write
    def save_clip(
        self,
        session: Session,
        clip: CreateClip,
        video_id: UUID | str,
    ) -> Clip:
        """Saves a clip to the database."""
        valid_clip = Clip.model_validate(clip)
        video = session.exec(select(Video).where(Video.id == video_id)).first()
        if video is None:
            raise ValueError(f"Video with id {video_id} not found")
        video.clips.append(valid_clip)
        session.add(video)
        session.commit()
        session.refresh(video)
        session.refresh(valid_clip)
        clip_query = (
            select(Clip)
            .where(Clip.id == valid_clip.id)
            .options(selectinload(Clip.words))  # type: ignore - selectinload type is weird
        )
        # need to do this extra query to load the words eagerly
        final_clip = session.exec(clip_query).first()
        if final_clip is None:
            raise ValueError(f"Clip with id {valid_clip.id} not found")
        return final_clip

    @write
    def save_clips(
        self,
        session: Session,
        clips: Sequence[CreateClip],
        video_id: UUID | str,
    ) -> Sequence[Clip]:
        video = session.exec(select(Video).where(Video.id == video_id)).first()
        clips_valid = []
        if video is None:
            raise ValueError(f"Video with id {video_id} not found")
        for clip in clips:
            clips_valid.append(Clip.model_validate(clip))
        video.clips.extend(clips_valid)
        session.add(video)
        session.commit()
        session.refresh(video)
        clips_query = (
            select(Clip)
            .where(Clip.video_id == video.id)
            .options(selectinload(Clip.words))  # type: ignore - selectinload type is weird
        )
        return session.exec(clips_query).all()

